INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es01ablxk9mq', NULL, 'me-despidieron-despues-de-8-anos-en-la-empresa', 'career', 'Me despidieron después de 8 años en la empresa', 'Entré con 24 años. Hice de todo: capacité gente nueva, cubrí licencias, me quedé hasta las 10 de la noche más veces de las que puedo contar. A los 8 años me citaron a una sala chica con alguien de RRHH que no conocía. Me dijeron que era una reestructuración. Me dieron un sobre con la liquidación y me pidieron que entregara la notebook ese mismo día. No me dejaron ni despedirme de los compañeros. Salí a la calle con una caja de cartón y no supe para dónde caminar.', 'es', 1, 'published', 0, '{"metoo":18,"hug":14,"strength":6,"respect":5,"solidarity":3}', 0, 1, 1760412800);
