INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es02cbnyk4nr', NULL, 'renuncie-a-un-trabajo-estable-por-una-startup-que-cerro-en-4-meses', 'career', 'Renuncié a un trabajo estable por una startup que cerró en 4 meses', 'Tenía contrato indefinido, obra social y aguinaldo. Me ofrecieron ser head de producto en una startup con "mucho potencial". Dupliqué el sueldo en papel. Renuncié un viernes, el lunes siguiente ya estaba en la oficina nueva llena de plantas y pizarrones con frases motivacionales. A los cuatro meses el CEO mandó un mail a las 11 de la noche diciendo que cerraban por falta de financiamiento. No cobré el último mes. Volví a buscar trabajo como si nunca hubiera tenido nada.', 'es', 1, 'published', 0, '{"metoo":9,"hug":5,"strength":3,"respect":2,"solidarity":1}', 0, 1, 1761500000);
