INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es03dcozl5ps', NULL, 'me-ignoraron-en-la-promocion-que-merecia', 'career', 'Me ignoraron en la promoción que merecía', 'Llevaba tres años liderando proyectos que técnicamente no eran mi responsabilidad. Mi jefa me dijo en la evaluación que era "imprescindible" y que estaba "lista para el siguiente nivel". Dos semanas después anunciaron que promovían a un compañero que había llegado hace ocho meses. Cuando pregunté, me dijeron que él "encajaba mejor con la visión de largo plazo". Tenía dos años menos de experiencia y nunca había entregado nada a tiempo. Seguí siendo imprescindible, sin el sueldo que correspondía.', 'es', 1, 'published', 0, '{"metoo":14,"hug":6,"strength":4,"respect":7,"solidarity":2}', 0, 1, 1762800000);
