INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es04edpam6qt', NULL, 'falle-una-presentacion-importante-y-mi-carrera-se-freno', 'career', 'Fallé una presentación importante y mi carrera se frenó', 'Era la revisión trimestral con los directores. Llevaba una semana preparando las diapositivas. Me trabé en el tercer slide, perdí el hilo, tuve que pedir que me repreguntaran algo que ya habían preguntado. Silencio incómodo. Uno de los directores empezó a revisar el teléfono. Terminé como pude. En los meses siguientes me sacaron de las reuniones estratégicas. Nunca nadie me dijo nada directamente, pero los proyectos interesantes empezaron a ir a otros. Así estuve dos años hasta que me fui.', 'es', 1, 'published', 0, '{"metoo":11,"hug":4,"strength":3,"respect":3,"solidarity":2}', 0, 1, 1764200000);
