INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es05feqbn7ru', NULL, 'trabaje-gratis-6-meses-como-pasantia-que-nunca-se-convirtio-en-empleo', 'career', 'Trabajé gratis 6 meses como pasantía que nunca se convirtió en empleo', 'Me dijeron que era una prueba de 3 meses con posibilidad de incorporación. A los 3 meses me pidieron "un poco más de tiempo para evaluar el presupuesto". Seguí. A los 6 meses me reuní con el gerente que me dijo que no había "encaje cultural". Pregunté qué significaba eso y no supo explicármelo. Mientras tanto cubrí a dos personas que renunciaron, armé el proceso de onboarding para los nuevos y diseñé tres campañas que usaron. No cobré un peso en todo ese tiempo.', 'es', 1, 'published', 0, '{"metoo":16,"hug":8,"strength":2,"respect":6,"solidarity":4}', 0, 1, 1765400000);
