INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es06gfrcm8sv', NULL, 'me-contrataron-y-me-despidieron-antes-de-empezar', 'career', 'Me contrataron y me despidieron antes de empezar', 'Firmé el contrato, renuncié a mi trabajo anterior, avisé a los compañeros, hice una cena de despedida. Faltaban tres días para empezar cuando me llamó la persona de RRHH para decirme que hubo "un cambio en la estructura interna" y que lamentablemente no iban a poder incorporarme. Me ofrecieron un mes de indemnización "de buena voluntad" que tardaron dos meses en depositar. Mientras tanto yo ya había dejado el departamento, porque pensaba mudarme al nuevo trabajo. Fueron seis meses muy complicados.', 'es', 1, 'published', 0, '{"metoo":7,"hug":9,"strength":2,"respect":3,"solidarity":4}', 0, 1, 1766800000);
