INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es07hgsdn9tw', NULL, 'hice-todo-bien-y-me-reemplazaron-por-alguien-mas-barato', 'career', 'Hice todo bien y me reemplazaron por alguien más barato', 'Cinco años consecutivos con evaluación "supera expectativas". Nunca un problema, siempre disponible. Me llamaron a una reunión donde me explicaron que iban a "optimizar la estructura de costos". Mi reemplazo entró dos semanas después: recién recibido, sin experiencia, a la mitad de mi sueldo. Estuve tres meses capacitándolo porque "era lo profesional". Después me fui. El pibe duró seis meses y renunció. Nunca me llamaron.', 'es', 1, 'published', 0, '{"metoo":21,"hug":7,"strength":3,"respect":8,"solidarity":2}', 0, 1, 1768000000);
