INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('eskgrxkfgkd5', NULL, 'burnout-silencioso-trabaje-2-anos-al-150-y-termine-sin-nada', 'career', 'Burnout silencioso: trabajé 2 años al 150% y terminé sin trabajo ni salud', 'Nunca dije que no. Siempre disponible, siempre respondiendo a las 11 de la noche. Me decía a mí mismo que era temporario. El segundo año empecé a tener taquicardias antes de abrir el mail. El médico me dijo síndrome de burnout y me recomendó licencia. Pedí la licencia y en dos semanas me llamaron para decirme que "reorganizarían el área". Me fui con la salud hecha pedazos y sin poder dormir más de cuatro horas. Tardé un año en poder trabajar de nuevo con normalidad.', 'es', 1, 'published', 0, '{"metoo":12,"hug":17,"strength":5,"respect":4,"solidarity":3}', 0, 1, 1769501234);
