INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esghoycnfbje', NULL, 'me-creyeron-demasiado-mayor-para-el-puesto-a-los-38', 'career', 'Me creyeron demasiado mayor para el puesto a los 38', 'Apliqué a un puesto para el que tenía exactamente el perfil. Primera entrevista bien, segunda bien. En la tercera me preguntaron mi edad directamente. Cuando dije 38, el tono cambió. Me dijeron que buscaban alguien que pudiera "crecer con la empresa a largo plazo". Tengo 38, no 62. El que entraron tiene 26 y tardó nueve meses en entender lo que yo haría desde el primer día. Me lo contó alguien de adentro. No me sirvió de nada saberlo.', 'es', 1, 'published', 0, '{"metoo":8,"hug":5,"strength":2,"respect":4,"solidarity":1}', 0, 1, 1770802468);
