INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es85krhzedby', NULL, 'estudie-5-anos-para-una-carrera-sin-mercado', 'career', 'Estudié 5 años para una carrera sin mercado', 'Cuando entré a la facultad todos me decían que era una carrera con salida. Me recibí, mandé currículums durante ocho meses, fui a entrevistas donde me preguntaban si también sabía hacer otras cosas. Terminé trabajando en algo completamente diferente por necesidad. Los cinco años, las materias, los finales, el esfuerzo. Todo eso existe pero no aparece en ningún lugar de mi vida cotidiana. No me arrepiento de haber estudiado, pero sí de haberme creído que eso alcanzaba.', 'es', 1, 'published', 0, '{"metoo":6,"hug":4,"strength":2,"respect":2,"solidarity":1}', 0, 1, 1771500102);
