INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('essm54vebx2j', NULL, 'trabaje-remoto-para-una-empresa-que-quebro-sin-pagarme', 'career', 'Trabajé remoto para una empresa que quebró sin pagarme el último mes', 'Tres años trabajando para una empresa del exterior. Siempre puntual en los pagos hasta el último mes. Empezaron a demorar, después me dijeron que había "un problema técnico con la transferencia". A la quinta semana el CEO desapareció del Slack. El dominio de la empresa empezó a redirigir a una página en blanco. Me debían cuatro semanas de trabajo. Inicié acciones legales internacionales que no llegaron a ningún lado. Perdí ese mes y también la confianza en el trabajo remoto.', 'es', 1, 'published', 0, '{"metoo":5,"hug":3,"strength":1,"respect":2,"solidarity":2}', 0, 1, 1772101336);
