INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esop46y57b8p', NULL, 'me-cortaron-el-sueldo-a-la-mitad-temporalmente', 'career', 'Me cortaron el sueldo a la mitad "temporalmente" y nunca volvió', 'Pandemia, crisis, entendí. Acepté la reducción del 50% "por tres meses". Pasaron tres meses, después seis, después un año. Cada vez que preguntaba me decían que "la situación todavía era delicada". A los catorce meses renuncié. En la carta de renuncia puse exactamente por qué. El gerente me respondió que lo entendía y que era "una lástima". Me debían diez meses de diferencia salarial que nunca reclamé porque el juicio me iba a salir más caro en tiempo y energía. Así funciona esto.', 'es', 1, 'published', 0, '{"metoo":13,"hug":6,"strength":2,"respect":4,"solidarity":3}', 0, 1, 1772802570);
