INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es9anvfxsea2', NULL, 'abri-un-bar-con-mis-ahorros-de-10-anos-duro-14-meses', 'business', 'Abrí un bar con mis ahorros de 10 años, duró 14 meses', 'Vendí el auto, usé los ahorros de diez años, pedí prestado a mi viejo. El local era perfecto: esquina, buena zona, techo alto. Los primeros tres meses llenos, pensé que lo había logrado. Después empezó el verano, la gente se fue, los costos no bajaron. Hice delivery, eventos privados, promociones. Igual las deudas crecieron más rápido que los ingresos. Cerré un martes a la tarde. Me llevó dos años terminar de pagar lo que debía. Todavía paso por la esquina y me duele.', 'es', 1, 'published', 0, '{"metoo":9,"hug":12,"strength":4,"respect":5,"solidarity":3}', 0, 1, 1773500204);
