INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('espyt99h82nv', NULL, 'lance-una-app-de-delivery-y-rappi-entro-ese-mismo-mes', 'business', 'Lancé una app de delivery local y Rappi entró al mercado ese mismo mes', 'Dos años de desarrollo, plata de mi familia, un equipo de tres personas. Lanzamos en marzo. En abril Rappi anunció su expansión a nuestra ciudad con descuentos del 50% financiados por ellos. Los restaurantes que habían firmado con nosotros empezaron a pedirnos salir del contrato. En dos meses perdimos el 80% de los socios comerciales. Cerramos en julio. Los inversores recuperaron algo, el equipo nada, yo quedé con deuda y sin proyecto. El timing lo es todo y nadie te lo enseña.', 'es', 1, 'published', 0, '{"metoo":4,"hug":7,"strength":3,"respect":5,"solidarity":2}', 0, 1, 1774001438);
