INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esc89rw9jupv', NULL, 'mi-socio-se-fue-con-los-clientes-y-el-capital', 'business', 'Mi socio se fue con los clientes y el capital', 'Empezamos juntos, mitad y mitad. Yo ponía el know-how, él los contactos. Funcionó bien tres años. Un día llegué a la oficina y la mitad de las cosas no estaban. Me enteré por un cliente que llamó preguntando por el nombre de la nueva empresa de mi ex socio. Se había llevado la cartera de clientes que habíamos construido juntos, el 60% del capital de la cuenta compartida y a dos empleados. El contrato social que habíamos firmado era tan genérico que el abogado me dijo que no había mucho para hacer.', 'es', 1, 'published', 0, '{"metoo":6,"hug":8,"strength":2,"respect":4,"solidarity":3}', 0, 1, 1774602672);
