INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es23sbdb7s12', NULL, 'el-local-que-alquile-tenia-problemas-legales-y-perdi-el-deposito', 'business', 'El local que alquilé tenía problemas legales y perdí el depósito', 'Pagué tres meses de depósito y el primer mes adelantado. Hice reformas por mi cuenta por casi el mismo valor. A los dos meses el propietario recibió una intimación judicial por una deuda hipotecaria que arrastraba el inmueble desde antes de que yo firmara. El local quedó trabado legalmente. No pude operar, no pude recuperar el depósito ni el dinero de las reformas. El propietario desapareció. El juicio sigue abierto tres años después. No tengo expectativas.', 'es', 1, 'published', 0, '{"metoo":3,"hug":5,"strength":1,"respect":2,"solidarity":2}', 0, 1, 1760800306);
