INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esaf17zvotwk', NULL, 'pedi-un-prestamo-para-el-negocio-y-no-pude-pagarlo', 'business', 'Pedí un préstamo para el negocio y no pude pagarlo', 'El banco me aprobó el crédito con una tasa que parecía razonable cuando proyecté los números. El negocio arrancó bien pero más lento de lo esperado. La inflación empujó los costos hacia arriba más rápido que los ingresos. A los ocho meses estaba usando el capital de trabajo para pagar las cuotas del crédito. Cerré el negocio, refinancié la deuda a peores condiciones y estuve tres años pagando algo que ya no existía. El banco cobró todo igual.', 'es', 1, 'published', 0, '{"metoo":7,"hug":4,"strength":2,"respect":3,"solidarity":2}', 0, 1, 1761601540);
