INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es6u79l86y1e', NULL, 'inveirt-en-franquicia-y-la-marca-quebro', 'business', 'Invertí en franquicia y la marca quebró', 'Pagué el canon de franquicia, acondicioné el local a su estándar, contraté personal según su protocolo. Dieciocho meses de operación con números razonables. Después la casa central entró en concurso preventivo, después en quiebra. De un día para el otro no tenía proveedor, no tenía marca y no podía usar ninguno de los materiales que me habían vendido. El contrato de franquicia tenía una cláusula que me impedía reconvertir el local a otra marca durante dos años. Perdí todo lo invertido y después algo más.', 'es', 1, 'published', 0, '{"metoo":4,"hug":6,"strength":2,"respect":3,"solidarity":1}', 0, 1, 1762402774);
