INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esc4x0zuwe1b', NULL, 'hice-dropshipping-8-meses-nunca-llegue-al-punto-de-equilibrio', 'business', 'Hice dropshipping 8 meses, nunca llegué al punto de equilibrio', 'Me lo vendieron como el negocio perfecto: sin stock, sin inversión inicial, desde casa. Ocho meses después había gastado más en publicidad en Meta que lo que había cobrado en ventas. Las devoluciones llegaban a mi nombre aunque yo no tenía los productos. Los proveedores demoraban los envíos y los clientes me escribían a mí. Pasé dos meses durmiendo mal por las notificaciones. El último mes facturé cero y gasté en ads lo que me quedaba de ahorro. Cerré sin drama porque ya no quedaba nada que cerrar.', 'es', 1, 'published', 0, '{"metoo":5,"hug":3,"strength":1,"respect":2,"solidarity":1}', 0, 1, 1763400408);
