INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esjqso9s8qd4', NULL, 'mi-ecommerce-crecio-meti-stock-y-las-ventas-se-cayeron', 'business', 'Mi ecommerce creció, metí stock, y las ventas se cayeron', 'Dos años construyendo la tienda online de a poco. Llegué a un mes récord y decidí escalar: importé producto, alquilé depósito, contraté un empleado part-time. El mes siguiente las ventas cayeron un 40%. El siguiente otro 30%. Nunca supe bien por qué. Cambió el algoritmo, cambió la competencia, cambié yo también quizás. Terminé vendiendo el stock a precio de costo durante seis meses, pagando el depósito vacío y desvinculando al empleado después de tres meses. Todo lo que había acumulado en dos años, deshecho en uno.', 'es', 1, 'published', 0, '{"metoo":6,"hug":5,"strength":2,"respect":3,"solidarity":2}', 0, 1, 1764801642);
