INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esbb8vupzbho', NULL, 'hice-un-posgrado-de-2-anos-que-no-vale-nada-en-el-mercado', 'education', 'Hice un posgrado de 2 años que no vale nada en el mercado', 'Dos años, veinte mil dólares en cuotas, un título que nadie me preguntó en ninguna entrevista. El posgrado prometía inserción en la industria y networking internacional. El networking era con otros estudiantes igual de perdidos que yo. La inserción nunca existió. En las entrevistas de trabajo nadie me preguntó por el posgrado. Me contrataron, siempre, por lo que había hecho antes de hacerlo. Sigo pagando la última cuota.', 'es', 1, 'published', 0, '{"metoo":10,"hug":4,"strength":2,"respect":3,"solidarity":2}', 0, 1, 1765602876);
