INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esbofsqltlai', NULL, 'rendi-el-ingreso-a-medicina-4-veces-nunca-quede', 'education', 'Rendí el ingreso a medicina 4 veces, nunca quedé', 'Cuatro años consecutivos preparando el ingreso. Primer año quedé a seis puntos. Segundo año a tres. Tercero me puse un profesor particular, estudié nueve meses de corrido, rendí y quedé afuera por cuatro décimas. El cuarto año ya no era lo mismo. Rendí, no quedé, y algo se terminó adentro mío. Tengo 26 años y todavía no sé bien qué hacer con todo el tiempo que le di a eso. No sé si sentir alivio o vacío.', 'es', 1, 'published', 0, '{"metoo":7,"hug":9,"strength":3,"respect":4,"solidarity":2}', 0, 1, 1766300510);
