INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esr903z9z21j', NULL, 'me-echaron-de-la-universidad-por-copiar-un-trabajo', 'education', 'Me echaron de la universidad por un trabajo que copié sin entender las consecuencias', 'Tercer año, parcial domiciliario, entregué algo que no era mío. No lo hice con malicia calculada, lo hice porque estaba desbordado y no encontré otra salida en ese momento. Me detectaron, me citaron, me explicaron el reglamento y me aplicaron la sanción más grave: expulsión. Perdí tres años de carrera, la beca, el departamento que compartía con otros estudiantes de la facultad. Nunca pude inscribirme en otra universidad del país porque quedé en el registro. Fue un error de diez minutos que cambió todo.', 'es', 1, 'published', 0, '{"metoo":3,"hug":11,"strength":4,"respect":2,"solidarity":5}', 0, 1, 1767101744);
