INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('eshplda0mx2g', NULL, 'abandone-ingenieria-en-4to-ano-y-no-se-si-fue-un-error', 'education', 'Abandoné ingeniería en 4to año y no sé si fue un error o no', 'Cuatro años de una carrera que odiaba pero que seguí porque era lo que se esperaba de mí. En cuarto año dejé de ir. No lo anuncié, simplemente dejé de aparecer. Mi familia tardó seis meses en darse cuenta. Cuando se enteraron fue una crisis familiar de proporciones. Hoy trabajo en otra cosa que me gusta más, pero la pregunta sigue ahí: si hubiera aguantado un año más, si hubiera pivotado a otra ingeniería, si hubiera pedido ayuda. No tengo respuesta. Solo cuatro años que existieron y después no.', 'es', 1, 'published', 0, '{"metoo":8,"hug":6,"strength":3,"respect":3,"solidarity":2}', 0, 1, 1768202978);
