INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('eswakeb3jaaq', NULL, 'estudie-ingles-3-anos-y-sigo-sin-poder-mantener-una-conversacion', 'education', 'Estudié inglés 3 años y sigo sin poder mantener una conversación', 'Tres años de clases, dos profesores distintos, una app de idiomas que usé todos los días durante ocho meses. Puedo leer bien, entiendo películas si tengo subtítulos en inglés. Pero cuando alguien me habla en inglés me paralizo. En una entrevista de trabajo me preguntaron algo en inglés y respondí en español disculpándome. No conseguí el trabajo. Sigo estudiando porque no sé qué más hacer. Ya no sé si es el método o soy yo.', 'es', 1, 'published', 0, '{"metoo":11,"hug":5,"strength":2,"respect":2,"solidarity":1}', 0, 1, 1769000612);
