INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es4qj3bi1gyc', NULL, 'hice-una-especializacion-online-carisima-y-la-plataforma-desaparecio', 'education', 'Hice una especialización online carísima de una plataforma que desapareció', 'Dos mil dólares por una especialización de seis meses en una plataforma que prometía certificación internacional y acceso vitalicio al material. Terminé el curso, obtuve el certificado digital. Un año después la plataforma cerró. El certificado ya no tiene URL válida, no existe empresa que lo respalde, no hay forma de verificarlo. En las entrevistas me piden que lo compruebe y no puedo. El conocimiento quedó, el papel no vale nada. Y los dos mil dólares tampoco volvieron.', 'es', 1, 'published', 0, '{"metoo":6,"hug":4,"strength":1,"respect":3,"solidarity":2}', 0, 1, 1770101846);
