INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('eslebcxkrpsg', NULL, 'reprobe-el-final-de-tesis-despues-de-6-anos-de-carrera', 'education', 'Reprobé el final de tesis después de 6 años de carrera', 'Seis años de carrera, un año de tesis. La presenté en noviembre. El jurado me hizo preguntas que no esperaba, me trabé en dos respuestas clave, y al final me dijeron que tenía que reformular la parte empírica y volver a presentar. Salí de la sala y no pude hablar durante veinte minutos. Mis compañeros ya estaban trabajando con el título. Yo tuve que volver a empezar la tesis con el tema reformulado. Tardé ocho meses más. Nunca lo conté públicamente hasta ahora.', 'es', 1, 'published', 0, '{"metoo":5,"hug":10,"strength":4,"respect":3,"solidarity":3}', 0, 1, 1771003080);
