INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('eslxbvb7yrpi', NULL, 'me-separe-despues-de-9-anos-y-no-se-quien-soy-sin-esa-relacion', 'relationships', 'Me separé después de 9 años y no sé quién soy sin esa relación', 'Nueve años juntos. La mitad de mi vida adulta. Cuando nos separamos yo no sabía qué música me gustaba a mí solo, qué quería comer cuando no tenía que negociar con nadie, cómo hacer planes sin consultar. Me di cuenta de que había construido una identidad completamente entrelazada con otra persona y que por fuera de eso no había mucho. No extraño a esa persona específicamente. Extraño saber quién era cuando estaba con ella. Hace dos años de esto y sigo sin respuesta.', 'es', 1, 'published', 0, '{"metoo":9,"hug":15,"strength":5,"respect":4,"solidarity":3}', 0, 1, 1771800714);
