INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esxydokh355j', NULL, 'mi-mejor-amigo-me-presto-plata-y-se-convirtio-en-mi-peor-enemigo', 'relationships', 'Mi mejor amigo me prestó plata y se convirtió en mi peor enemigo', 'Le pedí prestado en un momento difícil, acordamos un plazo razonable. Al tercer mes le pagué la mitad. Al quinto le pagué el resto. Pensé que estaba todo bien. Unos meses después me enteré por otro amigo en común que él había estado contando a todo el grupo que yo "no le había pagado" y que había tenido que "insistir mucho". Era mentira. Tengo los comprobantes. Pero el daño ya estaba hecho. Esa amistad no existe más. Y la versión de mí que confió en él tampoco.', 'es', 1, 'published', 0, '{"metoo":6,"hug":7,"strength":2,"respect":4,"solidarity":3}', 0, 1, 1772501948);
