INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es7ata0sipxy', NULL, 'construi-toda-mi-red-en-una-empresa-y-cuando-me-fui-desaparecio', 'relationships', 'Construí toda mi red de contactos en una empresa y cuando me fui, desapareció', 'Ocho años en la misma empresa. Conocía a todo el mundo, me invitaban a todo, tenía acceso a cualquier puerta. Cuando renuncié para emprender, pensé que toda esa red era mía. No lo era. Era de la empresa. Los primeros meses nadie me respondía los mensajes con la misma velocidad. Las reuniones que antes conseguía en un día tardaban semanas. Algunos directamente dejaron de responder. Aprendí que construí capital social en una sola institución y que eso no se transfiere.', 'es', 1, 'published', 0, '{"metoo":7,"hug":5,"strength":2,"respect":5,"solidarity":2}', 0, 1, 1773203182);
