INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esr7isd3hk29', NULL, 'confie-en-un-socio-que-era-mi-amigo-de-la-infancia-y-me-estafo', 'relationships', 'Confié en un socio que era mi amigo de la infancia y me estafó', 'Treinta años de amistad. Le propuse un negocio, le confié el manejo de la cuenta bancaria porque él tenía más tiempo. Durante ocho meses retiró plata de la cuenta para gastos "operativos" que no eran reales. Cuando revisé los números y le pregunté, primero negó, después me bloqueó en todos lados. La cantidad no era enorme pero era todo lo que había puesto. Lo más difícil no fue el dinero. Fue entender que alguien que conocía desde chico era capaz de eso.', 'es', 1, 'published', 0, '{"metoo":4,"hug":9,"strength":3,"respect":3,"solidarity":4}', 0, 1, 1774200816);
