INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esxyywgqfjg1', NULL, 'me-pele-con-mi-familia-por-una-herencia-y-perdi-a-todos', 'relationships', 'Me peleé con mi familia por una herencia y perdí a todos', 'Cuando murió mi padre quedó un departamento y una confusión. Mi hermano interpretó el testamento de una manera, yo de otra. Los dos teníamos razón en algo. Contratamos abogados distintos y empezó un proceso judicial que duró cuatro años. Ganamos en términos legales, perdimos en términos humanos. Hoy no hablo con mi hermano ni con dos primas que tomaron partido por él. Mi madre murió en el medio de todo eso sin que la familia estuviera junta. El departamento lo vendimos y repartimos. No valió lo que costó.', 'es', 1, 'published', 0, '{"metoo":3,"hug":11,"strength":2,"respect":3,"solidarity":4}', 0, 1, 1775002050);
