INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esge3fv34lhp', NULL, 'una-amistad-de-15-anos-termino-de-un-dia-para-el-otro', 'relationships', 'Una amistad de 15 años terminó de un día para el otro sin explicación', 'No hubo pelea, no hubo traición, no hubo un momento específico. Un día dejó de responder los mensajes. Al principio pensé que estaba ocupado. Después pasaron semanas, después meses. Lo veía activo en redes, subiendo historias, respondiendo a otros. Mandé un último mensaje preguntando si estaba todo bien. Me respondió que "sí, que estaba con mucho trabajo". Después nada. Quince años de amistad, viajes juntos, momentos importantes. Terminó en silencio y nunca supe por qué.', 'es', 1, 'published', 0, '{"metoo":8,"hug":12,"strength":2,"respect":3,"solidarity":4}', 0, 1, 1775803284);
