INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esyk4sb7f6re', NULL, 'trabaje-enfermo-3-meses-hasta-que-el-medico-me-dijo-que-parara', 'health', 'Trabajé enfermo 3 meses hasta que el médico me dijo que tenía que parar', 'Tenía síntomas desde enero pero los ignoré porque no era el momento: deadline importante, equipo reducido, yo era el que más sabía del proyecto. En marzo el médico me dijo que tenía neumonía bilateral y que era una irresponsabilidad haber esperado tanto. Estuve tres semanas de licencia. Cuando volví el proyecto había seguido sin mí, bastante bien. Eso también dolió. Me di cuenta de que en tres meses de empeorar progresivamente nadie de la empresa me había preguntado cómo estaba.', 'es', 1, 'published', 0, '{"metoo":9,"hug":8,"strength":3,"respect":3,"solidarity":2}', 0, 1, 1761000918);
