INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es6k8hv5u9uw', NULL, 'tuve-depresion-y-perdi-el-trabajo-el-departamento-y-casi-la-pareja', 'health', 'Tuve depresión y perdí el trabajo, el departamento y casi la pareja', 'No fue de golpe. Fue de a poco. Primero dejé de salir, después de responder mensajes, después de levantarme a horario. El trabajo me avisó por escrito que iba a haber consecuencias. Hubo consecuencias. Perdí el trabajo, con él el sueldo, con el sueldo el departamento. Mi pareja se quedó, pero hubo meses donde no sé cómo. El psiquiatra me dijo que había esperado demasiado en pedir ayuda. Tenía razón. Recuperarse tomó casi dos años. Todavía hay días que cuesta.', 'es', 1, 'published', 0, '{"metoo":6,"hug":19,"strength":7,"respect":4,"solidarity":5}', 0, 1, 1762002152);
