INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('escges7gd2gm', NULL, 'me-opere-la-recuperacion-duro-el-doble-y-gaste-todos-los-ahorros', 'health', 'Me operé, la recuperación duró el doble, gasté todos los ahorros', 'La cirugía era programada, no urgente, pero necesaria. El médico dijo seis semanas de recuperación. A las seis semanas hubo una complicación que requirió una segunda intervención. La cobertura médica pagó la operación pero no todos los insumos, no la enfermera de las primeras semanas, no los medicamentos importados. Doce semanas sin poder trabajar, con gastos que no había previsto. Vacié los ahorros de cuatro años. Cuando pude volver a caminar bien, la cuenta bancaria estaba en cero.', 'es', 1, 'published', 0, '{"metoo":4,"hug":10,"strength":3,"respect":3,"solidarity":2}', 0, 1, 1763003386);
