INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esw1oyuzr9ox', NULL, 'empece-a-tomar-pastillas-para-rendir-mas-y-termine-dependiendo-de-ellas', 'health', 'Empecé a tomar pastillas para rendir más y terminé dependiendo de ellas', 'Un amigo me recomendó algo para estudiar más horas. Al principio era solo para los exámenes. Después para las presentaciones. Después para los días normales porque sin ellas me sentía lento. En seis meses lo que era ocasional se volvió diario. Cuando quise cortar, el síndrome de abstinencia duró dos semanas en las que no pude trabajar ni dormir. El psiquiatra me dijo que había desarrollado dependencia. El proceso para dejarlas duró casi un año y tuve que tomar licencia. Nunca lo supe hasta que fue tarde.', 'es', 1, 'published', 0, '{"metoo":3,"hug":14,"strength":5,"respect":3,"solidarity":4}', 0, 1, 1764001020);
