INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('essrovslra73', NULL, 'ignore-sintomas-2-anos-por-miedo-a-ir-al-medico', 'health', 'Ignoré síntomas 2 años por miedo a ir al médico', 'Sabía que algo no estaba bien desde hacía mucho. Me cansaba más de lo normal, tenía dolores que antes no tenía, algo estaba raro. No fui al médico por miedo a lo que podían decirme. Dos años. Cuando fui, el diagnóstico no era catastrófico pero requería tratamiento inmediato. El médico me dijo que si hubiera venido antes el proceso habría sido mucho más simple. No tengo forma de saber cuánto complicó la espera, pero sé que la complicó. El miedo a saber costó más que el problema en sí.', 'es', 1, 'published', 0, '{"metoo":10,"hug":9,"strength":4,"respect":4,"solidarity":3}', 0, 1, 1765002254);
