INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esjwothy4qj4', NULL, 'inveirt-en-criptomonedas-en-2021-perdi-el-80-en-6-meses', 'financial', 'Invertí en criptomonedas en 2021, perdí el 80% en 6 meses', 'Todo el mundo ganaba. Los grupos de Telegram, los videos de YouTube, los compañeros de trabajo. Entré en noviembre del 2021 con los ahorros de tres años. En mayo del 2022 había perdido el 80%. Seguí aguantando porque todos decían que iba a recuperarse. A los dos años recuperé algo, pero no todo. Lo que más duele no es la plata. Es haber tomado decisiones financieras importantes basándome en el ruido de internet. Nunca lo hablé con nadie porque me daba vergüenza.', 'es', 1, 'published', 0, '{"metoo":14,"hug":6,"strength":3,"respect":4,"solidarity":2}', 0, 1, 1766003488);
