INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esacdia36puw', NULL, 'sali-garante-de-un-familiar-no-pago-y-ahora-tengo-su-deuda', 'financial', 'Salí garante de un familiar, no pagó, y ahora tengo deuda en mi nombre', 'Mi primo necesitaba un garante para alquilar. Era mi primo, confiaba en él. Durante dos años pagó bien. En el tercero empezó a demorar, después dejó de pagar del todo. El propietario me ejecutó a mí como garante. Tuve que pagar seis meses de alquiler que no eran míos más las costas judiciales. Mi primo me dijo que no tenía plata y desapareció del grupo familiar. Quedé con una deuda de su alquiler en mi nombre, una relación familiar rota y la certeza de que nunca más voy a salir garante de nadie.', 'es', 1, 'published', 0, '{"metoo":8,"hug":7,"strength":2,"respect":3,"solidarity":3}', 0, 1, 1767001122);
