INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('es6avbupsdpw', NULL, 'me-gaste-los-ahorros-de-5-anos-en-un-viaje-que-cambiaria-todo', 'financial', 'Me gasté los ahorros de 5 años en un viaje "que cambiaría todo" y volví igual', 'Renuncié, vendí cosas, usé lo que había ahorrado en cinco años. Seis meses viajando por Europa y Asia. Era lo que siempre había querido. Volví. Nada cambió. Tenía que buscar trabajo de vuelta, en el mismo mercado, con el mismo perfil, con cero ahorros y seis meses de gap en el currículum que tenía que explicar en cada entrevista. El viaje fue hermoso. Pero el "cambio de perspectiva" que me prometía a mí mismo no llegó. Volví siendo básicamente la misma persona, solo que más pobre.', 'es', 1, 'published', 0, '{"metoo":7,"hug":5,"strength":2,"respect":3,"solidarity":2}', 0, 1, 1768502356);
