INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esc9d979kxrr', NULL, 'saque-una-tarjeta-de-credito-para-empezar-un-negocio-y-acumule-deuda', 'financial', 'Saqué una tarjeta de crédito para empezar un negocio y acumulé deuda sin el negocio', 'La idea era clara: usar la tarjeta para los gastos iniciales y pagar con los primeros ingresos del negocio. Los ingresos nunca llegaron. El negocio nunca terminó de arrancar. Pero el resumen llegó igual, todos los meses. Pagué el mínimo durante un año mientras los intereses acumulaban. Cuando finalmente hice los números me debía más de lo que había gastado originalmente. Tardé cuatro años en cancelar la deuda de un negocio que duró tres meses. Nunca puse un peso en otra tarjeta de crédito.', 'es', 1, 'published', 0, '{"metoo":9,"hug":5,"strength":2,"respect":3,"solidarity":2}', 0, 1, 1769803590);
