INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('esxwe96nk1uz', NULL, 'le-preste-plata-a-una-empresa-como-inversion-y-nunca-la-vi-mas', 'financial', 'Le presté plata a una empresa como "inversión" y nunca la vi más', 'Un conocido tenía una empresa que necesitaba liquidez a corto plazo. Me ofreció un interés del 20% a tres meses. Firmamos algo informal, nada legal. A los tres meses me pidió dos meses más. A los cinco meses el teléfono empezó a no responder. A los siete meses la empresa no existía en ningún registro. Consulté un abogado que me dijo que sin un instrumento legal adecuado tenía muy poco que hacer. Era plata que me había llevado un año y medio juntar. Nunca apareció.', 'es', 1, 'published', 0, '{"metoo":6,"hug":4,"strength":1,"respect":3,"solidarity":2}', 0, 1, 1770901224);
